var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>클리포트 게임</color> 승전, 보름 뒤","JPN":"<color=#ffd34c>クリフォトゲーム</color>勝利、2週間後","ENG":"<color=#ffd34c>Qliphoth Game</color> victory, 2 weeks later","TWN":"<color=#ffd34c>逆卡巴拉遊戲</color>勝利，半個月後"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"이야~ 프론트베이는 오늘도 햇볕이 따갑네요.","JPN":"いや～フロントベイは今日も日差しが熱いですね。","ENG":"Wow! The sun in Front Bay is hot as ever.","TWN":"哎呀～前灣今天的陽光也很刺眼呢。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"오늘은 이곳 프론트베이에서 화보 촬영을 진행하고 계신 스완 양을 어렵게 모셨답니다.","JPN":"本日はこのフロントベイで写真集の撮影を行っているスワンさんに、インタビューに応じていただきました。","ENG":"Today, we are meeting with Miss Swan who is in Front Bay for a photoshoot.","TWN":"今天我們在這裡難得邀請到正在進行拍攝的史旺。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"안녕하세요, 스완 양.","JPN":"こんにちは、スワンさん。","ENG":"Hello, Miss Swan.","TWN":"你好，史旺。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"정말 오래간만에 다시 작품 활동을 시작하셨는데 소감 한마디 들을 수 있을까요?","JPN":"本当に久しぶりに映像作品への出演を再開されましたが、感想を一言お願いします。","ENG":"You've returned to work after a long break. May I ask how you feel about it?","TWN":"你好像很久沒有重新開始創作了，能聽聽你的感想嗎？"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"영화가 아닌 드라마는 처음일 텐데, 벌써부터 대중들의 반응이 뜨겁던데요?","JPN":"映画ではなくドラマですよね。ドラマは初めてだと聞きましたが、反響がすごいですね。","ENG":"It's your first time away from the silver screen and doing a drama series, but the public's reaction is already so enthusiastic.","TWN":"這應該是你第一次離開銀幕，嘗試拍攝電視劇吧？觀眾們的反應已經非常熱烈了呢？"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 글쎄요. 원래 무대 출신이라 저에게 있어서도 이번 시도는 도전이랍니다.","JPN":"ふふ、そうですね。もともと舞台出身ですから、私にとっても今回の作品は挑戦なんです。","ENG":"Haha, well. Since my background comes from doing stages, I think this will be like a challenge to myself.","TWN":"呵呵，怎麼說呢。畢竟我是舞台出身，這次嘗試對我來說也是一種挑戰。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 이야기가 단막극이 아닌, 연속극이 된다는 게 말이죠.","JPN":"短編ではなくシリーズ物に出演するのは今回が初めてですから。","ENG":"It would mean that my story will not be a one-act play, but a serial drama.","TWN":"我的故事不再是獨幕劇，而是連續劇了。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"아하, 사람들은 스완 양을 영화 배우라고 알고 있는데, 원래 극단 출신이셨군요.","JPN":"ほお、スワンさんは映画の女優として知られていますが、劇団出身だったんですね。","ENG":"A-ha. The people normally know you as a movie star, but you were originally a stage actress.","TWN":"啊哈，人們都以為史旺是電影演員，原來你是劇團出身的啊。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네, 그래서 긴장을 많이 했는데 스태프분들께서 도와주셔서 편하게 연기할 수 있었죠.","JPN":"はい、それでとても緊張したんですが、スタッフの皆さんに助けられて、リラックスして演じることができました。","ENG":"Yes. I used to be nervous whenever I was up on stage, but the staff helped me so that I could act comfortably.","TWN":"是的，當時的我還很緊張，但工作人員幫了我很多，讓我能夠安心表演。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"의외네요. 스완 양 같은 천재도 긴장이라는 걸 하다니.","JPN":"スワンさんのような天才も緊張するんですか？　意外ですね。","ENG":"That's surprising to hear. A genius like you getting nervous.","TWN":"真意外，像史旺這樣的天才也會緊張。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무대 위에 서면 항상 설레고 긴장되는 건 누구나 똑같은 걸요.","JPN":"舞台に立つといつもドキドキして緊張するのは、私でも同じなんです。","ENG":"Everyone feels excited and nervous whenever they're on stage.","TWN":"站在舞台上總是既興奮又緊張，這對每個人來說都是一樣的。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 절 지켜봐 주시는 팬분들을 실망시킬 수는 없으니까요.","JPN":"でも見守ってくださるファンの皆さんをがっかりさせる訳にはいきませんから。","ENG":"But I can't disappoint my fans.","TWN":"但是我不能讓支持我的粉絲們失望。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"언제나 우아하고, 아름답게 보이려고 노력하고 있답니다.","JPN":"常に優雅で、美しく見えるように努力しています。","ENG":"I try my best to look elegant and graceful.","TWN":"我一直在努力讓自己看起來優雅而美麗。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"역시 프로의 마음가짐은 무언가 다르네요.","JPN":"やっぱりプロの心構えはすごいですね！","ENG":"A professional's mindset is different, I see.","TWN":"果然，專業人士的心態就是不一樣。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"그러고 보니, 이번 작품은 본인이 직접 각본을 구상했다고 하던데요?","JPN":"そういえば、今回の作品はご自身で脚本を書かれたとか？","ENG":"Come to think of it, didn't you say you wrote the script?","TWN":"說起來，這次的作品聽說是你親自構思的劇本？"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네. 이번 작품은 처음부터 끝까지 제가 직접 관여하고 있습니다.","JPN":"はい、今回の作品は最初から最後まで私が直接関わらせていただいています。","ENG":"Yes. I was involved in this work from start to finish.","TWN":"是的。這次的作品從頭到尾都有我親自參與。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"각본뿐만이 아니라, 프로듀싱과 캐스팅, 로케이션 섭외 및 조연도 한자리 맡게 되었죠.","JPN":"脚本だけでなくプロデュースやキャスティング、ロケ地の手配、あと脇役を一つ担当しています。","ENG":"It's not just the script, but I was also responsible for the producing, casting, location selecting, and supporting roles.","TWN":"不僅僅是劇本，這次我還嘗試了製作、選角、場地安排，以及承擔了一些配角的飾演工作。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"조연이라고요?","JPN":"脇役ですか？","ENG":"Supporting roles?","TWN":"配角？"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"네. 사실, 전 선역보다는 악역을 선호하는 편이라서요.","JPN":"はい。実は私、悪役のほうが好みなんです。","ENG":"Yes. I tend to prefer villainous roles over good ones.","TWN":"是的。其實，我更喜歡反派角色。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 편이 팬분들께 좀 더 다채로운 연기를 보여드릴 수 있으니까요.","JPN":"その方が、ファンの皆さんに色んな演技をお見せすることができますしね。","ENG":"Because I'm able to show my fans a more diverse acting.","TWN":"這樣可以向粉絲們展示更多樣的演技。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"그러고보니 아침 드라마로 기획된 이야기치고 꽤 진지하다는 이야기를 들었는데요","JPN":"そういえば朝ドラとして企画された内容にしては、結構重いストーリーだと聞きました。","ENG":"I heard the story for this morning series is quite serious.","TWN":"這麼說來，我聽說這部作為晨間劇播出的作品，故事策劃蠻挺嚴肅的呢？"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 전세계 동시 송출이라 방영 시간대는 어디서 시청하시는지에 따라 다르겠죠.","JPN":"まあ、全世界同時配信なので時間帯は地域によって違いますからね。","ENG":"Well, it will be broadcast simultaneously all around the world, so I think it will feel different depending on where you watch it.","TWN":"這個嘛，由於全球同步播出，播放時間會因你所在的地區而異。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"작품이 정말로 진정성을 갖는다면, 방영 시간대는 크게 의미가 없지 않을까요?","JPN":"作品の本気が伝われば、放送時間帯はあまり関係ないんじゃないでしょうか。","ENG":"If we all put our 100 percent into the series, I don't think when it is aired will have a great significance.","TWN":"如果作品真的有誠意，播放時間應該沒那麼重要吧？"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"하하, 아티스트의 귀감이라고 할 수 있는 도전적인 발언이네요.","JPN":"はは、アーティストの鑑ともいえる挑戦的な発言ですね。","ENG":"Haha. That's a bold statement coming from a role model artist.","TWN":"哈哈，這真是藝術家的典範，充滿挑戰性的發言啊。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"그래서 작품에 관해 한 마디 들을 수 있을까요?","JPN":"作品についても一言、コメントをいただけるでしょうか。","ENG":"Could we get your comment about the series?","TWN":"那麼，可以聽你談談作品嗎？"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"흐음, 글쎄요. 자세한 건 스포일러라 말씀드릴 수 없지만…….","JPN":"うーん、そうですね。詳細はネタバレになるので言えませんが……","ENG":"Hmm, well. I can't go into detail as it would be a spoiler...","TWN":"嗯，這個嘛。詳細的內容是劇透，所以不能說……"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어느 탐정과 조수인 소녀가 함께 여러 사건을 해결한다는 이야기랍니다.","JPN":"とある探偵と少女が、ともに様々な事件を解決していくお話です。","ENG":"It is a story about a detective and an assistant girl solving various mysteries.","TWN":"簡而言之，這是一個關於某位偵探和他的少女助手一起解決案件的故事。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>그라운드 원</color>","JPN":"管理局直轄都市<color=#ffd34c>グラウンド・ワン</color>","ENG":"Administration Direct Control City, <color=#ffd34c>Ground One</color>","TWN":"管理局直轄市<color=#ffd34c>G1</color>"},"stage":{"bg":"GROUND_ONE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>ADC G-1</color> 대균열 관측소 정문","JPN":"<color=#ffd34c>ADC G-1</color>大亀裂観測所正門","ENG":"<color=#ffd34c>ADC G-1</color> Grand Dimension Crevice Observation Post Main Entrance","TWN":"<color=#ffd34c>ADC G-1</color>大峽谷觀測所正門"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"……호오, 그렇군요. 벌써부터 이야기가 흥미진진한데요?","JPN":"……ほお、そうですか。今から楽しみですね！","ENG":"...Ho-oh, I see. The story already sounds so exciting.","TWN":"……喔？是嗎？聽起來已經很有趣了呢。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L48_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"아쉽지만, 저희가 준비한 스완 양과의 인터뷰는 여기까지랍니다.","JPN":"とても残念ですが、スワンさんのインタビューは一旦ここまでとさせていただきます。","ENG":"Unfortunately, our interview with Miss Swan had to end here.","TWN":"很遺憾，時間有限，我們與史旺的採訪到此為止。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"그럼, 다음 소식은 샤레이드 건틀렛 리그에 관한 소식인데요.","JPN":"次のニュースはシャレードのガントレットリーグのニュースです。","ENG":"Then, our next news is about Charade's Gauntlet league.","TWN":"那麼，接下來是關於聖鎧聯賽的消息。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"지난 건틀렛 경기 중 같은 팀 동료를 쏜 와일러 선수의 재판 결과가…….","JPN":"前回のガントレットの試合で同じチームの仲間を撃ったワイラー選手の裁判結果が……","ENG":"The verdict of Wyler, who shot a teammate in the last Gauntlet match...","TWN":"在上次聖鎧比賽中，射擊同隊隊友的瓦勒選手，法院已經宣判對他的審判結果……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"아아, 부럽구만, 부러워.","JPN":"あ～あ、羨ましいな。","ENG":"Aah, I'm so jealous.","TWN":"啊啊，真羡慕啊。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"왜 그러십니까?","JPN":"どうしましたか？","ENG":"What is it, sir?","TWN":"怎麼了？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"프론트베이에서 근무하는 동기 녀석한테 들었는데.","JPN":"フロントベイで勤務してる同期のやつに聞いたんだけどさ。","ENG":"I heard from a colleague who works in Front Bay.","TWN":"我聽在前灣工作的同事說的。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"스완이 화보 촬영 때문에 그쪽 대균열 관측소를 방문했던 모양이야.","JPN":"スワンが写真集の撮影でそっちの大亀裂観測所を訪ねたらしくて。","ENG":"It looks like Swan visited their observatory at the Grand Dimension Crevice for a photoshoot.","TWN":"史旺好像因為拍攝去了那邊的觀測所。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"스완이 그 녀석 헬멧에다가 사인을 해줬다고 자랑하더라니까?","JPN":"ヘルメットにサインしてもらったって自慢されたよ。","ENG":"He bragged to me about how Swan signed his helmet.","TWN":"在那傢伙的頭盔上簽了名，現在在跟我炫耀呢！？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"네? 대균열 관측소는 민간인 접근 금지 구역 아닙니까?","JPN":"え？　大亀裂観測所って民間人は立ち入り禁止じゃないんですか？","ENG":"What? Isn't the observatory at the Grand Dimension Crevice off-limits to civilians?","TWN":"呃？大峽谷觀測所不是禁止平民進入的嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"그렇지 않아도 얼마전에 현실붕괴가 발생해서 난리가 나지 않았습니까?","JPN":"この前も現実崩壊が発生して大変だったじゃないですか。","ENG":"There was even a reality collapse that happened recently over there, right?","TWN":"就算沒有，前不久還發生了現實崩潰現象，那裡不是早就鬧翻天了嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"그땐 진짜 세상이 망해버리는 줄 알았는데…….","JPN":"あの時は本当に世界が滅ぶかと思いましたよ……","ENG":"I really thought the world was ending at the time...","TWN":"那時候我真以為世界要毀滅了……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"낸들 아냐?","JPN":"俺だって知らねえよ。","ENG":"How am I supposed to know?","TWN":"誰知道？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"그쪽은 맨날 해적이랑 헌터들이 현상금 때문에 들락날락하니까.","JPN":"向こうは海賊やらハンターやらが懸賞金目当てで出たり入ったりしてるから。","ENG":"Pirates and hunters come and go over there all the time to collect their bounty.","TWN":"那邊老是有海盜和獵人為了賞金進進出出的。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"대균열 근처가 침식지대로 묶여 있는 그라운드 원보단 규정이 널널할지도 모르지.","JPN":"大亀裂の周りが侵食地帯として規制されているグラウンド・ワンよりは緩いかもよ。","ENG":"Maybe the restrictions over there are more lenient than Ground One, where a Corrupted Area is near the Grand Dimension Crevice.","TWN":"也許比起附近被劃為侵蝕區的G1，規矩要寬鬆一點呢？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"아니면 그쪽 VIP가 흔쾌히 촬영 허가를 내줬을지도 모르고.","JPN":"それか、向こうのVIPが撮影許可を出してくれたのかもしれないし。","ENG":"Or, maybe their VIP gave her permission to film.","TWN":"或者是那邊的大人物爽快地批了特權也說不定。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"프론트베이 시니어님이요?","JPN":"フロントベイのシニアが？","ENG":"The Front Bay Senior?","TWN":"前灣的Senior？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"그래, 프론트베이 VIP는 엄청 호쾌한 사람이라고 들었거든.","JPN":"ああ、フロントベイのVIPは結構豪快な人だって聞いたぞ。","ENG":"Yeah. I heard Front Bay's VIP is a bit of a philanthropist.","TWN":"是啊，我聽說前灣的Senior是個非常豪爽的人。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"콧대만 높은 우리 깐깐한 VIP 씨와는 다르게 말이지.","JPN":"傲慢で口うるさいだけのうちのVIPとは違ってな。","ENG":"Unlike our VIP who's haughty and picky.","TWN":"不像我們的那位，真是高傲又挑剔。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"쳇, 지난 현실붕괴 사태만해도 그래.","JPN":"ちっ、この前の現実崩壊の時もそうだよ。","ENG":"Tch. Even looking at the recent reality collapse.","TWN":"哼，就拿上次發生的現實崩潰來說吧。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"대균열에 갑자기 괴물이 나타난 걸, 왜 우리 탓을 하냐고?","JPN":"大亀裂にいきなり化け物が現れたのは俺たちのせいじゃないだろ。","ENG":"Why is it our fault that a monster suddenly appeared from the Grand Dimension Crevice?","TWN":"大峽谷裡突然出現了怪物，為什麼要怪我們？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"저…… 선배님. 그……!","JPN":"あの……先輩、その……！","ENG":"Uh... sir. Um...!","TWN":"我……前輩。那個……！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"뭐? 왜? 또 너만 착한 놈이다 이거야? 너도 나랑 같이 감봉당했잖냐?","JPN":"あ？　なんだよ、またお前だけいい人ぶってんのか？　お前も俺と一緒に給料削減されただろ。","ENG":"Huh? What? Oh, I'm the bad guy here? But you also got a pay cut, didn't you?","TWN":"什麼那個？又要開始裝無辜嗎？你不也和我一起被降職了嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"까놓고 말해서 그걸 우리가 불렀어?","JPN":"ぶっちゃけ、別に俺たちがあれを呼んだわけじゃないのにさ。","ENG":"I mean, did we summon that thing?","TWN":"說實話，那東西又不是我們叫來的。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"우린 그냥 매뉴얼대로 했는데 왜 우리한테 히스테리를 부리는 건데?","JPN":"俺たちはマニュアルどおりにやったのに、なんで俺たちに八つ当たりするんだよ？","ENG":"We just did everything by the book, so why was she being hysterical to us?","TWN":"我們只是按照手冊做事，為什麼要對我們發脾氣？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"서, 선배님. 저, 그러니까…….","JPN":"せ、先輩。あの、ですから……","ENG":"E-erm, s-sir...?","TWN":"前，前輩。我，那個……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"가뜩이나 사건사고 많은 G-1으로 배치된 것도 힘들어 죽겠는데.","JPN":"ただでさえ事件が多いG-1に配置されて大変だっていうのによ。","ENG":"I already dread being assigned to G-1, as incidents happen every second.","TWN":"本來被分配到事故頻繁的G1，已經快累死了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"자기가 시니어면 다야? 성격이 그 모양이니까 아직도 결혼을 못하지.","JPN":"シニアってそんなに偉いのか？　性格があんなんだからまだ結婚もできないんだろ。","ENG":"I mean, so what if she's a Senior? She's got to fix that attitude of hers if she wants to get married.","TWN":"Senior就了不起嗎？那種性格，難怪到現在還沒結婚。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……그래?","JPN":"……そうか。","ENG":"...Oh yeah?","TWN":"……是嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그것참 궁금하네. 대체 내 성격이 어떻길래 그럴까?","JPN":"詳しく聞きたいな。私の性格がどうかしたのか？","ENG":"Now I'm curious. So what about my attitude?","TWN":"真是好奇啊，到底我是哪種性格？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"시, 시, 시, 시 시니어님……!?","JPN":"し、し、し、シニア……！？","ENG":"M-m-m-m-ma'am...?!","TWN":"S，S，S，Senior……！?"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"여긴 어떻게……?","JPN":"ここにはなぜ……？","ENG":"Why are you here...?","TWN":"你怎麼會……？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"어떻게냐니? 내가 내 도시를 돌아다니는데 누구 허락 맡고 다녀야 하는 거야?","JPN":"なぜ？　自分の都市を歩くのに、誰かの許しが必要なのか？","ENG":"Why am I here? Do I need your permission to patrol around my city?","TWN":"什麼怎麼會？我在自己的城市裡走動，還需要誰的許可嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"그, 그게 아니라…….","JPN":"そ、そうではなくて……","ENG":"I-it's not that...","TWN":"不，不是……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"시니어님께서는 오늘 최고 관리자 회의의 결정사항을 통보하러 가신다고…….","JPN":"シニアは今日、最高管理者会議の決定事項を通告しに行かれると……","ENG":"I heard that you were going to inform others of the decisions made in the Supreme Administrator meeting today...","TWN":"你今天不是要去通知最高管理者會議的決定嗎……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……르네 말루프.","JPN":"……ルネ・マルーフ。","ENG":"...Renée Maalouf.","TWN":"……芮妮·瑪盧夫。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그라운드 원 시니어. 퓨처 엣 워의 선임 연구원 출신.","JPN":"グラウンド・ワンのシニア。フューチャーアットウォーの専任研究員出身。","ENG":"Ground One Senior. Former Future-at-War senior researcher.","TWN":"G1的Senior，前天啟兵器高級研究員。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"15세부터 공학자로서 재능을 인정받음. 퓨처 엣 워 프로젝트 몰락 후 관리국에 합류.","JPN":"15歳から工学者としての才能を認められた。フューチャーアットウォープロジェクトの解散後、管理局に合流。","ENG":"Recognized for her talents as an engineer since the age of fifteen. Joined the Administration after the fall of the Future-at-War project.","TWN":"自15歲就被認可為工程師，天啟兵器項目失敗後加入了管理局。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지나친 과시 욕구와 편집증적 독립성은 이 시절 형성된 것으로 추정.","JPN":"行き過ぎた誇示欲求と、強迫的な独立性はこの時期に形成されたものと思われる。","ENG":"Assumed that her excessive desire to show off and obsessiveness for independence seemed to have formed during this time.","TWN":"推測她過度的炫耀慾和偏執的獨立性，便是在這個時期形成的。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"성과주의자. 승부욕이 강한 동시에 인정 욕구 또한 강함.","JPN":"成果主義者。負けず嫌いで、承認欲求が強い。","ENG":"Performance-oriented. Has a strong competitive spirit, while also having a strong need for recognition.","TWN":"成果主義者，既有強烈的勝負欲，又有強烈的認同需求。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"취미는 종합격투기. 스타일은 그래플링……. 이 또한 높은 자존심의 발로.","JPN":"趣味は総合格闘技。スタイルはグラップリング……これもまた、高いプライドの現れ。","ENG":"Hobbies include MMA. A grappler... Also a sign of high self-esteem.","TWN":"興趣是綜合格鬥，風格是摔跤……這也是高自尊心的表現。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"칭찬에 약한 편이지만, 노골적으로 드러나면 역효과……. 자길 깔본다고 생각하는군.","JPN":"褒められることに弱いが、露骨すぎると逆効果……甘く見られていると思うから。","ENG":"Weak to compliments, but backfires if too obvious... Thinks that she is looked down on.","TWN":"雖然對稱讚很受用，但如果太露骨反而會適得其反……會覺得在看不起她。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"좋아하는 음식은 스테이크. 굽기는 레어. 샤레이드에 자주 가는 가게가 두 곳 있음.","JPN":"好きな食べ物はステーキ。焼き加減はレア。シャレードに行きつけの店が二か所ある。","ENG":"Favorite food is steak. Cooked rare. There are two restaurants she frequents.","TWN":"喜歡的食物是牛排，三分熟。有兩家常去的店在查雷德。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이런 성격에, 이런 커리어라면 틀림없이 남자 보는 눈도 한없이 높겠군.","JPN":"こういう性格、こういうキャリアなら男を見る目も高いに違いない。","ENG":"With her personality and career, she must have high standards for men.","TWN":"有這樣的性格和這樣的職業，眼光肯定也高得不得了。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어지간한 주변 사람이나, 부하직원은 성에 안 차겠지.","JPN":"周りの人間や部下では、彼女の基準を満たす人はいないはず。","ENG":"She won't be interested in anyone around her or even her subordinates.","TWN":"周圍的一般人或下屬肯定不放眼裡吧。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……그렇다면.","JPN":"……それなら。","ENG":"...Then.","TWN":"……那麼。"},"stage":{"bg":"DOCUMENTS","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면, 여기서 르네 말루프라는 배역에 알맞은 대사는…….","JPN":"ここでルネ・マルーフとして正しい台詞は……","ENG":"Then, the appropriate line to say for the role of Renée Maalouf here would be...","TWN":"那麼，適合芮妮·瑪盧夫這個角色的台詞是……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"웃기지 마, 네가 왜 내 일정을 마음대로 규정하지?","JPN":"何様のつもりだ？　なぜ私のスケジュールを勝手に決めつける。","ENG":"Don't make me laugh, who are you to set my schedule?","TWN":"別開玩笑了，你有什麼資格隨便安排我的行程？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"네가 뭐라도 되는 줄 알아?","JPN":"あなたにそんな権限はないはずだろ？","ENG":"You think you're some bigshot, huh?","TWN":"你以為你是誰？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"네? 아, 아니, 그게 아니라…….","JPN":"え？　い、いや、そうじゃなくて……","ENG":"Ma'am? N-no, it's just that...","TWN":"啊，不是，那個……"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"코핀 컴퍼니의 압수수색은 순조롭게 진행되고 있어. 여긴 잠시 들린 것뿐이야.","JPN":"コフィンカンパニーの家宅捜索は順調に進んでいる。ここには少し寄ってみただけだ。","ENG":"Coffin Company's search and seizure is going smoothly. I'm just stopping by.","TWN":"對科芬公司的搜查進行得很順利。我只是暫時來這裡看看。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"하, 하하……. 그렇군요.","JPN":"は、はは……そ、そうですか。","ENG":"Ha, haha... I see.","TWN":"哈，哈哈……原來如此。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"보고는 받았어. 내가 없는 사이에 여기서 현실붕괴가 있었다면서?","JPN":"報告は受けた。私が留守の間、現実崩壊があったそうだな。","ENG":"I got your report. There was a reality collapse while I was absent, right?","TWN":"我已經收到報告了。在我不在的時候，這裡發生了現實崩潰現象？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그라운드 원 대균열에는 구 관리국 시절에 만들어진 붕괴 억제 장치라는 게 있을 거야.","JPN":"グラウンド・ワンの大亀裂には、旧管理局時代に作られた崩壊抑制装置があるはずだ。","ENG":"There should be a collapse prevention device made in the Old Administration days in Ground One's Grand Dimension Crevice.","TWN":"在G1的大峽谷中，應該有舊管理局時期製造的崩壞抑制裝置吧？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"억제 장치 말씀입니까?","JPN":"抑制装置ですか？","ENG":"A prevention device?","TWN":"抑制裝置？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그래, 나도 공학자야.","JPN":"そう、私は工学者だ。","ENG":"Yeah, I'm an engineer too.","TWN":"嗯，別忘了我也是工程師。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그걸 분석할 수 있다면 저번 사태의 원인을 규명할 수도 있겠지.","JPN":"その分析ができれば、先日の事態の原因を突き止めることもできるだろう。","ENG":"We'll be able to determine the cause of it if we can analyze it.","TWN":"如果能分析那個，也許就能查明上次事件的原因。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그러니 잠시 현장을 둘러봐야겠어. 준비해.","JPN":"だから少し現場を視察する。準備しろ。","ENG":"So, I'll need to have a look around. Get ready.","TWN":"所以我會先去現場看看。幫我準備好。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"그렇지만 대균열이 있는 곳은 침식현상이 잦습니다.","JPN":"しかし、大亀裂がある場所は侵食現象が頻繁に起こります。","ENG":"But the Grand Dimension Crevice experiences frequent Counterside Effects.","TWN":"但是，大峽谷附近經常會發生侵蝕現象。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"게다가 최근 여러 사태로 대균열의 경계 레벨은 몇 단계나 상향된 상태입니다.","JPN":"それに最近の色んな事態で、大亀裂の警戒レベルは何段階も引き上げられています。","ENG":"And due to the recent events, the alert level of the Grand Dimension Crevice has been raised by several levels.","TWN":"而且，最近由於多種事態，大峽谷的警戒等級已經提升了好幾個階段。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"야, 임마……!","JPN":"おい、お前……！","ENG":"Hey...!","TWN":"喂，喂……！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"두 번 말하게 하지 마. 이터니움 실드는 이미 챙겼으니까.","JPN":"二度も言わせるな。エタニウムシールドは用意してある。","ENG":"Don't make me say it twice. I've already brought the Eternium shield.","TWN":"別讓我說第二遍，永恆之金護盾我已經拿來了。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"그럼, 저희가 호위로 붙겠습니다. 괜찮으시겠습니까?","JPN":"では、私たちが護衛としてつきます。それで大丈夫でしょうか。","ENG":"Then, we will act as your guards. Will that be okay?","TWN":"那麼，我們來護衛你。可以嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……좋아.","JPN":"……構わない。","ENG":"...All right.","TWN":"……很好。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이쪽은 그럭저럭 일을 잘하네.","JPN":"こっちはまあまあ仕事ができるやつらだな。","ENG":"This one seems to know his assignment.","TWN":"看來你倒是還算機靈。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"안내해.","JPN":"案内しろ。","ENG":"Lead the way.","TWN":"帶路。"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>ADC G-1</color> 대균열 인근 지역 <color=#ffd34c>CSE LV.2</color>","JPN":"<color=#ffd34c>ADC G-1</color>大亀裂近隣地域<color=#ffd34c>CSE LV.2</color>","ENG":"<color=#ffd34c>ADC G-1</color> Area near the Grand Dimension Crevice <color=#ffd34c>CSE Lv. 2</color>","TWN":"<color=#ffd34c>ADC G-1</color> 大峽谷附近區域 <color=#ffd34c>CSE Lv.2</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"여기부터는 대균열로부터 흘러나온 침식파의 영향을 상시로 받는 구역입니다.","JPN":"ここからは、大亀裂から漏れ出た侵食波の影響に常時露出されている区域です。","ENG":"From here, this area is constantly affected by Corruption rays flowing from the Grand Dimension Crevice.","TWN":"從這裡開始是受到大峽谷侵蝕波影響的區域。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"현재 대균열은 안정화되어 상시 CSE 레벨 1 ~ 2를 유지하고 있습니다만…….","JPN":"現在大亀裂は安定化して常時CSEレベル1～2を維持していますが……","ENG":"The Grand Dimension Crevice has been currently stabilized and maintaining a CSE Level between 1 and 2...","TWN":"目前大峽谷已經穩定，維持在常時CSE等級1～2……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"그래도 침식지대는 침식지대입니다.","JPN":"それでも侵食地帯ということには変わりありません。","ENG":"But a Corrupted Area is still a Corrupted Area.","TWN":"不過畢竟是侵蝕地帶。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"혹시 모를 돌발상황에 항상 대비해주십시오.","JPN":"万が一の事態に備えてください。","ENG":"Please be prepared for the unexpected.","TWN":"請時刻準備應對突發情況。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……이상하네.","JPN":"……おかしい。","ENG":"...That's odd.","TWN":"……真奇怪。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"여기부터는 관측 장비들이 하나도 보이지 않는데? 이렇게 방치해도 문제없는 거야?","JPN":"ここからは観測装備が一つも見当たらないな。こんな状態で放置してもいいのか？","ENG":"I don't see any observation device from here. Is it okay to leave it unchecked like this?","TWN":"從這裡開始就看不到任何觀測設備了？這樣放任不管沒問題嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"대균열로부터 반경 2킬로미터 부근까지는 감시 장비를 투입할 수 없습니다.","JPN":"大亀裂より半径2キロメートルまでは、監視装備を配置できません。","ENG":"Detection devices can't be deployed within a two-kilometer radius of the Grand Dimension Crevice.","TWN":"在距離大峽谷半徑2公里的範圍內，無法投入監視設備。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"아무리 낮은 레벨이라고 해도, 장시간 침식파에 노출되면 오류가 발생하거든요.","JPN":"いくらレベルが低いとはいえ、長時間侵食波に露出されるとエラーを起こしてしまいます。","ENG":"Even if the level is low, an error occurs when it's exposed to Corruption rays for long.","TWN":"即使是再低等級的侵蝕波，長時間暴露其中也會發生故障。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"대침식 장비라면 괜찮은 물건들이 시중에도 꽤 있을 텐데?","JPN":"耐侵食装備なら高性能のものが結構あるだろう。","ENG":"Aren't there a few good products out on the market when it comes to an anti-Corruption device?","TWN":"如果是抗侵蝕裝備的話，市面上應該有不少好東西的吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"물론, 최고급 장비라면 보다 오래 버틸 수는 있겠지만…….","JPN":"もちろん、最高級の装備なら長く耐えることはできますが……","ENG":"Of course, the top-of-the-line equipment can last longer, but...","TWN":"當然，頂級裝備可能會堅持更久一些……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"그래봤자, 비싼 소모품 수준입니다. 결국 상시 투입하기에는 예산상 문제가 있어요.","JPN":"所詮は高いだけの消耗品に過ぎません。常時投入するには予算的にきついです。","ENG":"even so, it's only an expensive consumable item. Eventually, there will be budgetary issues when it comes to constantly deploying them.","TWN":"即便如此，也不過是昂貴的消耗品而已。最終要常規投入的話，預算上會有問題。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_A","text":{"KOREA":"야, 무슨 쓸데없는 소리를……!","JPN":"おい、余計なことを……！","ENG":"Hey, why are you telling her that...?","TWN":"喂，你幹嘛說出來……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"대신 현재는 경계 레벨이 상향되어, 한 시간에 한 번 순찰을 수행하고 있습니다.","JPN":"その代わり現在は警戒レベルが引き上げられたので、一時間ごとに見回りを行っています。","ENG":"Instead, we are patrolling the perimeter every hour due to the increase in the alert level.","TWN":"所以，我們提高了警戒級別，每小時會進行一次巡邏。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 무슨 말인지 이해했어.","JPN":"よし、状況は理解した。","ENG":"All right. I understand what you're saying.","TWN":"好的，我明白你的意思了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"나름 고생이 많네. 도시관리국에 돌아가면 예산편성을 검토해 볼게.","JPN":"それなりに苦労しているな。都市管理局に戻ったら、予算編成を再検討してみよう。","ENG":"Good work. I'll review the budget allocation once I return to City Management.","TWN":"你們也蠻辛苦的。我回去以後，會重新考慮預算分配的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"감사합니다.","JPN":"ありがとうございます。","ENG":"Thank you.","TWN":"非常感謝。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"붕괴 억제 장치까지는 조금만 더 가면 됩니다.","JPN":"あと少しで崩壊抑制装置のところに着きます。","ENG":"It's a little further to the collapse prevention device.","TWN":"那麼，再走一點就到崩壞抑制裝置了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ADMINSOLDIER_SWANSONG_NPC_B","text":{"KOREA":"……음?","JPN":"……む？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ADMINSOLDIER_SWANSONG_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"그르르르르르, 그으으으윽……!!","JPN":"グルルルルル、グルル……！！","ENG":"Grr.... Grrrrrrr...!!","TWN":"呃嗚嗚嗚嗚，呃噢噢噢……！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_01"},{"id":"L30_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"저 침식체는……?","JPN":"あの侵食体は……？","ENG":"Is that a C.O....?","TWN":"那侵蝕體是……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};